import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public List<String> removeSubfolders(String[] folder) {
    List<String> result = new ArrayList<>();
    Arrays.sort(folder);
    String prefix = "/";

    for (String path : folder) {
        if (!path.startsWith(prefix)) {
            result.add(path);
            prefix = path + "/";
        }
    }
    return result;
}
```

